import React from 'react';
import { useNavigate } from 'react-router-dom';
import DashboardLayout from '../components/DashboardLayout';
import { Orb, StatCard, GlassCard } from '../components/UI';
import { useAuth } from '../context/AuthContext';

export default function AdminDashboard() {
  const navigate = useNavigate();
  const { user } = useAuth();

  return (
    <DashboardLayout>
      <div className="grid-bg" style={{ padding: 28, minHeight: '100vh', position: 'relative' }}>
        <Orb color="#f59e0b" size={180} left="-50px" top="-40px" opacity={0.08} />

        <h1 style={{ fontSize: 24, fontWeight: 700, marginBottom: 6 }} className="gradient-text-warm">
          Admin Dashboard
        </h1>
        <p style={{ color: 'rgba(226,232,240,0.45)', fontSize: 12, marginBottom: 20 }}>
          Welcome, {user?.name || 'Admin'}
        </p>

        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit,minmax(160px,1fr))', gap: 12, marginBottom: 18 }}>
          <StatCard icon="🛡️" label="ROLE" value="ADMIN" sub="Restricted access" color="#f59e0b" />
          <StatCard icon="👥" label="USERS" value="Live" sub="Manage candidates" color="#00f5ff" />
          <StatCard icon="📊" label="ANALYTICS" value="Overview" sub="Platform insights" color="#8b5cf6" />
        </div>

        <GlassCard style={{ padding: 18 }}>
          <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 10 }}>Quick Actions</div>
          <div style={{ display: 'flex', gap: 10, flexWrap: 'wrap' }}>
            <button className="btn btn-cyan" onClick={() => navigate('/leaderboard')}>Leaderboard</button>
            <button className="btn btn-purple" onClick={() => navigate('/profile')}>Profile</button>
            <button className="btn btn-primary" onClick={() => navigate('/dashboard')}>Candidate View</button>
          </div>
        </GlassCard>
      </div>
    </DashboardLayout>
  );
}
